    def get_atr(self, candles):
        if not candles or len(candles) < 15:
            return None
        highs = [float(c[2]) for c in candles]
        lows = [float(c[3]) for c in candles]
        closes = [float(c[4]) for c in candles]
        return self._atr(highs, lows, closes, 14)

    def _ema(self, data, period):
        ema = [0.0] * len(data)
        ema[0] = data[0]
        k = 2.0 / (period + 1)
        for i in range(1, len(data)):
            ema[i] = data[i] * k + ema[i-1] * (1 - k)
        return ema

    def _rsi(self, data, period=14):
        deltas = [data[i] - data[i-1] for i in range(1, len(data))]
        gains = [d if d > 0 else 0 for d in deltas]
        losses = [-d if d < 0 else 0 for d in deltas]
        avg_gain = sum(gains[-period:]) / period
        avg_loss = sum(losses[-period:]) / period
        if avg_loss == 0:
            return 100.0
        rs = avg_gain / avg_loss
        return 100.0 - (100.0 / (1.0 + rs))

    def _atr(self, highs, lows, closes, period=14):
        trs = []
        for i in range(1, len(highs)):
            tr = max(highs[i] - lows[i], abs(highs[i] - closes[i-1]), abs(lows[i] - closes[i-1]))
            trs.append(tr)
        return sum(trs[-period:]) / min(period, len(trs)) if trs else 0

    def _adx(self, highs, lows, closes, period=14):
        if len(highs) < period + 1:
            return 0
        plus_dm = [max(highs[i] - highs[i-1], 0) for i in range(1, len(highs))]
        minus_dm = [max(lows[i-1] - lows[i], 0) for i in range(1, len(lows))]
        atr = self._atr(highs, lows, closes, period)
        if atr == 0:
            return 0
        plus_di = sum(plus_dm[-period:]) / period / atr * 100
        minus_di = sum(minus_dm[-period:]) / period / atr * 100
        di_sum = plus_di + minus_di
        if di_sum == 0:
            return 0
        return abs(plus_di - minus_di) / di_sum * 100

    def _macd(self, data, fast=12, slow=26, signal=9):
        ema_fast = self._ema(data, fast)
        ema_slow = self._ema(data, slow)
        macd_line = [ema_fast[i] - ema_slow[i] for i in range(len(data))]
        signal_line = self._ema(macd_line, signal)
        histogram = [macd_line[i] - signal_line[i] for i in range(len(data))]
        return macd_line, signal_line, histogram

